                     'MarkerFaceColor', 'k', 'LineWidth', 1.5); %[output:1be9b59d]

% --- Brute-force optimum (red) ---
% Trail of past optima
h_trail_brute_force   = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), '-', ... %[output:1be9b59d]
                     'Color', [1 0 0 0.4], 'LineWidth', 1.2); %[output:1be9b59d]
% Past optimum markers (dim red)
h_past_brute_force    = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), 'rx', ... %[output:1be9b59d]
                     'MarkerSize', 8, 'LineWidth', 1.0, ... %[output:1be9b59d]
                     'Color', [1 0.6 0.6]); %[output:1be9b59d]
% Current optimum (bright red)
h_opt_brute_force         = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), 'rx', ... %[output:1be9b59d]
                     'MarkerSize', 16, 'LineWidth', 2.5); %[output:1be9b59d]

xlabel('$n_{\psi_x}$','Interpreter','latex'); %[output:1be9b59d]
ylabel('$n_{\psi_y}$','Interpreter','latex'); %[output:1be9b59d]
